import { useNavigate } from "react-router-dom";
import { slugify } from "../../../utils/slugify";
import { BlogType } from "../../../data/blogType";

type RelatedBlogsProps = {
  blogs: BlogType[];
};

const RelatedBlogs = ({ currentBlogId, category }: RelatedBlogsProps) => {
  const navigate = useNavigate();

  // Filter blogs by same category, exclude current blog, and limit to 3
  const displayedRelatedBlogs = blogData
    .filter((blog) => blog.category === category && blog.id !== currentBlogId)
    .slice(0, 3);

  if (displayedRelatedBlogs.length === 0) return null;

  return (
    <>
      <div className="w-full max-w-[1440px] mx-auto h-auto py-14">
        <h1 className="text-center text-[50px] font-black leading-tight mb-12">
          Related blogs
        </h1>

        <div className="flex justify-between items-center space-x-6 px-28 pb-36">
          {blogs.map((blog) => (
            <div
              key={blog.id}
              className="relative w-full grid grid-cols-3 items-center justify-center transition-all duration-500 ease-in-out"
            >
              <div
                onClick={() => navigate(`/blog/${slugify(blog.title)}`)}
                className="cursor-pointer relative min-w-[390px] max-w-full h-[500px] rounded-lg bg-white/5 overflow-hidden group transition-all duration-300 ease-in-out"
                style={{
                  boxShadow: `
                  inset 0 -5px 5px rgba(255, 255, 255, 0.01),
                  inset 0 2px 1.5px rgba(255, 255, 255, 0.05)
                `,
                }}
              >
                <img
                  src={blog.image}
                  className="w-full h-full object-cover rounded-lg group-hover:scale-110 transition-all duration-700 ease-in-out"
                  alt={blog.title}
                />

                <span
                  className="absolute top-5 left-5 bg-black rounded-lg px-4 py-1 capitalize"
                  style={{
                    boxShadow: `
                    inset 0 -5px 5px rgba(255, 255, 255, 0.01),
                    inset 0 1.5px 1.5px rgba(255, 255, 255, 0.15)
                  `,
                  }}
                >
                  {blog.category}
                </span>
              </div>
              <span className="absolute top-[104%]">
                <h1 className="text-[23px] font-black leading-7">
                  {blog.title}
                </h1>
                <p className="mt-2 text-[17px] leading-6 opacity-70">
                  {blog.description}
                </p>
              </span>
            </div>
          ))}
        </div>
      </div>
    </>
  );
};

export default RelatedBlogs;
